rss.channel:
{{ if eq .Title .Site.Title }}{{ .Site.Title }}{{ else }}{{ with .Title }}{{.}} on {{ end }}{{ .Site.Title }}{{ end }}
{{ .Permalink }}
Recent content {{ if ne .Title .Site.Title }}{{ with .Title }}in {{.}} {{ end }}{{ end }}on {{ .Site.Title }}
Hugo -- gohugo.io
{{ with .Site.Language.Locale }}{{.}}{{end}}
{{ with .Site.Params.author.email }}{{.}}{{ with $.Site.Params.author.name }} ({{.}}){{end}}{{end}}
{{ with .Site.Params.author.email }}{{.}}{{ with $.Site.Params.author.name }} ({{.}}){{end}}{{end}}
{{ with .Site.Copyright }}{{.}}{{end}}
{{ if not .Date.IsZero }}{{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" | safeHTML }}{{ end }}
{{ with .OutputFormats.Get "RSS" }}
    {{ printf "" .Permalink .MediaType.Type | safeHTML }}
{{ end }}

{{- $pages := slice -}}
{{- if or .IsHome .IsSection -}}
    {{- $pages = .RegularPages -}}
{{- else -}}
    {{- $pages = .Pages -}}
{{- end -}}

{{- /* Remove private items first */ -}}
{{- $pages = where $pages "Params.private" "!=" true -}}

{{- /* Gather everything within the last 2 years */ -}}
{{- $twoYearsAgo := now.AddDate -2 0 0 -}}
{{- $recentPages := where $pages "Date" "ge" $twoYearsAgo -}}

{{- /* Logic: If 2-year count is less than 3, force-fallback to exactly the 3 newest posts total */ -}}
{{- if lt (len $recentPages) 3 -}}
    {{- $pages = first 3 $pages -}}
{{- else -}}
    {{- $pages = $recentPages -}}
{{- end -}}

{{- range $pages -}}


  {{ .Title }}
  {{ .Permalink }}
  {{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" | safeHTML }}
  {{ with .Site.Params.author.email }}{{.}}{{ with $.Site.Params.author.name }} ({{.}}){{end}}{{end}}
  {{ .Permalink }}
  {{- with .Params.featured_image -}}

  {{- end -}}
  {{ .Summary | html }}

{{- end -}}
